const company = $('Fetch Companies for Intent Check').first().json;
const news = $('Search Company News').first().json.articles || [];
const jobs = $('Check Recent Job Postings').first().json.jobs || [];

return [{
  json: {
    company_name: company.name,
    company_id: company.id,
    news_count: news.length,
    job_count: jobs.length,
    news_headlines: news.slice(0, 5).map(a => a.title).join(' | '),
    job_titles: jobs.slice(0, 10).map(j => j.title).join(', '),
    linkedin_activity: company.linkedin_activity || '',
    website_changes: company.recent_website_changes || 'none'
  }
}];

