parameters.jsCode:
const claude = $input.first().json;
const company = $('Aggregate Intent Data').first().json;

let analysis;
try {
  analysis = JSON.parse(claude.content[0].text);
} catch (e) {
  const match = claude.content[0].text.match(/\{[\s\S]*\}/);
  analysis = match ? JSON.parse(match[0]) : {
    intent_score: 0,
    intent_level: 'low',
    key_signals: [],
    urgency: 'low',
    recommended_action: 'wait',
    reasoning: 'Parse error'
  };
}

return [{
  json: {
    company_id: company.company_id,
    company_name: company.company_name,
    intent_score: analysis.intent_score,
    intent_level: analysis.intent_level,
    key_signals: analysis.key_signals.join('; '),
    urgency: analysis.urgency,
    recommended_action: analysis.recommended_action,
    reasoning: analysis.reasoning,
    analyzed_at: new Date().toISOString()
  }
}];
